-- Run this script in your Supabase SQL Editor to insert 25 mock users
-- Note: This script inserts into auth.users (to satisfy foreign keys and auth) 
-- and then updates public.profiles (which are auto-generated by the trigger).

-- Enable pgcrypto for password hashing if not already enabled
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DO $$
DECLARE
  -- Generate 25 UUIDs
  u1 UUID := gen_random_uuid(); u2 UUID := gen_random_uuid(); u3 UUID := gen_random_uuid(); u4 UUID := gen_random_uuid(); u5 UUID := gen_random_uuid();
  u6 UUID := gen_random_uuid(); u7 UUID := gen_random_uuid(); u8 UUID := gen_random_uuid(); u9 UUID := gen_random_uuid(); u10 UUID := gen_random_uuid();
  u11 UUID := gen_random_uuid(); u12 UUID := gen_random_uuid(); u13 UUID := gen_random_uuid(); u14 UUID := gen_random_uuid(); u15 UUID := gen_random_uuid();
  u16 UUID := gen_random_uuid(); u17 UUID := gen_random_uuid(); u18 UUID := gen_random_uuid(); u19 UUID := gen_random_uuid(); u20 UUID := gen_random_uuid();
  u21 UUID := gen_random_uuid(); u22 UUID := gen_random_uuid(); u23 UUID := gen_random_uuid(); u24 UUID := gen_random_uuid(); u25 UUID := gen_random_uuid();
  default_pass TEXT := crypt('password123', gen_salt('bf'));
BEGIN

  -- 1. Insert into auth.users (This will trigger public.handle_new_user() and create empty profiles)
  INSERT INTO auth.users (id, instance_id, aud, role, email, encrypted_password, email_confirmed_at, raw_app_meta_data, raw_user_meta_data, created_at, updated_at)
  VALUES
  (u1, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user1@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Alex Chen"}', now(), now()),
  (u2, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user2@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Sarah Jenkins"}', now(), now()),
  (u3, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user3@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Mike Ross"}', now(), now()),
  (u4, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user4@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Elena Gilbert"}', now(), now()),
  (u5, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user5@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"David Kim"}', now(), now()),
  (u6, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user6@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Rachel Zane"}', now(), now()),
  (u7, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user7@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Harvey Specter"}', now(), now()),
  (u8, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user8@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Donna Paulsen"}', now(), now()),
  (u9, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user9@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Louis Litt"}', now(), now()),
  (u10, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user10@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Katrina Bennett"}', now(), now()),
