  (u13, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user13@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Samantha Wheeler"}', now(), now()),
  (u14, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user14@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Alex Williams"}', now(), now()),
  (u15, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user15@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Brian Altman"}', now(), now()),
