  (u19, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user19@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Sean Cahill"}', now(), now()),
  (u20, '00000000-0000-0000-0000-000000000000', 'authenticated', 'authenticated', 'user20@syncstudy.com', default_pass, now(), '{"provider":"email","providers":["email"]}', '{"full_name":"Daniel Hardman"}', now(), now()),
