  -- 2. Update the public.profiles table (which was auto-created by the trigger)
  -- Group 1: Computer Science, Sem 6, Python/Java, Night Owls (8 users)
  UPDATE public.profiles SET 
    college = 'Stanford University', branch = 'Computer Science', semester = 6, 
    subjects = '{"Data Structures", "Algorithms", "Machine Learning"}', exams = '{"GRE", "GATE"}', goals = 'Prepare for FAANG interviews', timings = 'night', learning_style = 'visual', language = 'English', verification_status = 'verified'
  WHERE id IN (u1, u2, u3, u4, u5, u6, u7, u8);

  -- Group 2: Mechanical Engineering, Sem 4, Thermodynamics/CAD, Early Birds (5 users)
  UPDATE public.profiles SET 
    college = 'MIT', branch = 'Mechanical Engineering', semester = 4, 
    subjects = '{"Thermodynamics", "AutoCAD", "Fluid Mechanics"}', exams = '{"GATE", "IES"}', goals = 'Complete semester projects', timings = 'morning', learning_style = 'practical', language = 'English', verification_status = 'verified'
  WHERE id IN (u9, u10, u11, u12, u13);

  -- Group 3: Computer Science, Sem 2, C/C++, Any time (5 users)
  UPDATE public.profiles SET 
    college = 'UC Berkeley', branch = 'Computer Science', semester = 2, 
    subjects = '{"Introduction to Programming", "Discrete Math"}', exams = '{"Midterms"}', goals = 'Pass finals with flying colors', timings = 'afternoon', learning_style = 'reading', language = 'English', verification_status = 'verified'
