    subjects = '{"Macroeconomics", "Corporate Finance", "Marketing"}', exams = '{"GMAT"}', goals = 'Case study preparations', timings = 'morning', learning_style = 'auditory', language = 'Spanish', verification_status = 'verified'
  WHERE id IN (u19, u20, u21, u22);

  -- Group 5: Outliers / Diverse subjects (3 users)
  UPDATE public.profiles SET 
    college = 'Oxford University', branch = 'Literature', semester = 8, 
    subjects = '{"Shakespeare", "Poetry"}', exams = '{"Thesis"}', goals = 'Write dissertation', timings = 'night', learning_style = 'reading', language = 'French', verification_status = 'verified'
  WHERE id = u23;

  UPDATE public.profiles SET 
    college = 'NYU', branch = 'Film Studies', semester = 3, 
    subjects = '{"Cinematography", "Screenwriting"}', exams = '{"Finals"}', goals = 'Complete short film', timings = 'afternoon', learning_style = 'visual', language = 'English', verification_status = 'verified'
  WHERE id = u24;

  UPDATE public.profiles SET 
    college = 'University of Tokyo', branch = 'Robotics', semester = 5, 
    subjects = '{"AI", "Mechatronics"}', exams = '{"JLPT"}', goals = 'Build a robot', timings = 'morning', learning_style = 'practical', language = 'Japanese', verification_status = 'verified'
  WHERE id = u25;

END $$;
